mapper.sql:
from aiw_news_article n
where n.is_deleted = 0

    and (lower(n.title) like concat('%', lower(#{criteria.keyword}), '%')
      or lower(coalesce(n.summary, '')) like concat('%', lower(#{criteria.keyword}), '%'))


    and n.article_type = #{criteria.articleType}


    and n.source_code = #{criteria.sourceCode}


    and n.language_code = #{criteria.languageCode}


    and n.publish_time >= #{criteria.publishFrom}


    and n.publish_time <= #{criteria.publishTo}

mapper.select:
select count(*) from aiw_news_article
where is_deleted = 0 and publish_time >= #{from}

    and (

        lower(concat(title, ' ', coalesce(summary, ''))) like
        concat('%', lower(#{keyword}), '%')

    )

select n.* 
order by ${sortColumn}

    asc
    desc

limit #{offset}, #{criteria.size}
